#include <iostream>
using namespace std;

int main() {
    int a, b, c, d;
    cin >> a >> b >> c >> d;

    long long product = 1;
    if (a < 5) product *= a;
    if (b < 5) product *= b;
    if (c < 5) product *= c;
    if (d < 5) product *= d;

    cout << product << endl;
    return 0;
}
